@app.route("/api/orders")
def get_orders():
    orders = db.execute("SELECT * FROM orders LIMIT 100").fetchall()

    result = []
    for order in orders:
        # BAD: one query per order to get the customer name
        customer = db.execute(
            "SELECT name FROM customers WHERE id = ?",
            (order["customer_id"],)
        ).fetchone()
        result.append({
            "id": order["id"],
            "total": order["total"],
            "customer_name": customer["name"],
        })

    return jsonify(result)  # 101 queries for 100 orders!
